starterCode.python:
class Solution:
    def bubbleSort(self, nums: List[int]) -> List[int]:
        n = len(nums)
        for i in range(n-1):
            swapped = False
            for j in range(n-1):
                if nums[j] > nums[j+1]:
                    nums[j], nums[j+1] = nums[j+1], nums[j]
                    swapped = True
            if not swapped:
                break
        return nums

starterCode.javascript:
function bubbleSort(nums) {
    let n = nums.length;
    let swapped = false;
    for (let i = 0; i < n - 1; i++) {
        for (let j = 0; j < n - 1; j++) {
            if (nums[j] > nums[j + 1]) {
                [nums[j], nums[j + 1]] = [nums[j + 1], nums[j]];
                swapped = true;
            }
        }
        if (!swapped) {
            break;
        }
    }
    return nums;
}

